        "GettingStarted": {
            "title": "GettingStarted",
            "text": "\\define lingo-base() $:/language/ControlPanel/Basics/\nШЁЩҮ ~TiddlyWiki ЩҲ Ш¬Ш§Щ…Ш№ЩҮвҖҢЫҢ  ~TiddlyWiki Ш®ЩҲШҙ ШўЩ…ШҜЫҢШҜ.\n\nЩӮШЁЩ„ Ш§ШІ Ш§ЫҢЩҶ Ъ©ЩҮ ЩҮШұ ЪҜЩҲЩҶЩҮ Ш§Ш·Щ„Ш§Ш№Ш§ШӘ Щ…ЩҮЩ…ЫҢ ШұЩҲ ШҜШұ ~TiddlyWiki ЩҲШ§ШұШҜ Ъ©ЩҶЫҢШҢ Щ…ЩҮЩ…ЩҮ Ъ©ЩҮ Ш§Ш·Щ…ЫҢЩҶШ§ЩҶ Ъ©ШіШЁ Ъ©ЩҶЫҢЩ… Ъ©ЩҮ Щ…ЫҢвҖҢШӘЩҲЩҶЫҢ Ш§Ш·Щ„Ш§Ш№Ш§ШӘ ШұЩҲ ШЁЩҮ ШҙЪ©Щ„ ЩӮШ§ШЁЩ„ Ш§Ш№ШӘЩ…Ш§ШҜЫҢ Ш°Ш®ЫҢШұЩҮ Ъ©ЩҶЫҢ. ШЁШұШ§ЫҢ Ш§Ш·Щ„Ш§Ш№Ш§ШӘ ШЁЫҢШҙШӘШұ ШЁШЁЫҢЩҶ: https://tiddlywiki.com/#GettingStarted\n\n!! Ш§ЫҢЩҶ ШұЩҲ ШӘЩҶШёЫҢЩ… Ъ©ЩҶ ~TiddlyWiki\n\n<div class=\"tc-control-panel\">\n\n|<$link to=\"$:/SiteTitle\"><<lingo Title/Prompt>></$link> |<$edit-text tiddler=\"$:/SiteTitle\" default=\"\" tag=\"input\"/> |\n|<$link to=\"$:/SiteSubtitle\"><<lingo Subtitle/Prompt>></$link> |<$edit-text tiddler=\"$:/SiteSubtitle\" default=\"\" tag=\"input\"/> |\n|<$link to=\"$:/DefaultTiddlers\"><<lingo DefaultTiddlers/Prompt>></$link> |<<lingo DefaultTiddlers/TopHint>><br> <$edit tag=\"textarea\" tiddler=\"$:/DefaultTiddlers\"/><br>//<<lingo DefaultTiddlers/BottomHint>>// |\n</div>\n\nШЁШұШ§ЫҢ Ш§ЩҶШӘШ®Ш§ШЁвҖҢЩҮШ§ЫҢ ШЁЫҢШҙШӘШұ Ш§ЫҢЩҶ ШұЩҲ ШЁШЁЫҢЩҶ: [[control panel|$:/ControlPanel]]\n"
        },
